import java.util.*;

public class Solution {
    public static long solve(long[] nums, long[][] edges) {
        int N = nums.length;

        // 1. Build Adjacency Matrix
        boolean[][] adj = new boolean[N][N];
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            adj[u][v] = true;
            adj[v][u] = true;
        }

        long count = 0;
        int totalMasks = 1 << N;

        // Iterate through all non-empty subsets S (represented by mask M)
        for (int M = 1; M < totalMasks; M++) {

            // --- Step 3: Check Sum Parity ---
            // The sum is even if the number of nodes i in M where nums[i] == 1 is even.
            int onesCount = 0;
            for (int i = 0; i < N; i++) {
                if (((M >> i) & 1) == 1 && nums[i] == 1) {
                    onesCount++;
                }
            }

            if (onesCount % 2 != 0) {
                continue; // Sum is odd
            }

            // --- Step 4: Check Connectivity ---

            // Find a starting node (the smallest index in M)
            int startNode = -1;
            for (int i = 0; i < N; i++) {
                if (((M >> i) & 1) == 1) {
                    startNode = i;
                    break;
                }
            }

            // If M is not empty, startNode must exist.

            // BFS Setup
            Queue<Integer> queue = new LinkedList<>();
            boolean[] visited = new boolean[N];

            queue.add(startNode);
            visited[startNode] = true;
            int connectedNodes = 0;

            while (!queue.isEmpty()) {
                int u = queue.poll();
                connectedNodes++;

                // Check neighbors v
                for (int v = 0; v < N; v++) {
                    // 1. Edge (u, v) must exist
                    // 2. v must be in the subset M
                    // 3. v must not have been visited yet
                    if (adj[u][v] && ((M >> v) & 1) == 1 && !visited[v]) {
                        visited[v] = true;
                        queue.add(v);
                    }
                }
            }

            // Check if the number of connected nodes equals the total size of the subset M
            int subsetSize = Integer.bitCount(M);
            if (connectedNodes == subsetSize) {
                count++;
            }
        }

        return count;
    }
}

